SELECT r.* FROM qc_reinspection_record r
LEFT JOIN qc_work_order w ON r.work_order_id = w.id


        AND (r.reinspection_no LIKE '%' || #{keyword} || '%' OR w.work_order_no LIKE '%' || #{keyword} || '%' OR w.harness_code LIKE '%' || #{keyword} || '%')


        AND r.status = #{status}


        AND r.reinspection_result = #{reinspectionResult}


        AND r.reinspection_time >= (#{dateFrom}::timestamp)


        AND r.reinspection_time <= ((#{dateTo}::date) + interval '1 day')


ORDER BY r.id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1) FROM qc_reinspection_record r LEFT JOIN qc_work_order w ON r.work_order_id = w.id
AND (r.reinspection_no LIKE '%' || #{keyword} || '%' OR w.work_order_no LIKE '%' || #{keyword} || '%' OR w.harness_code LIKE '%' || #{keyword} || '%')
AND r.status = #{status}
AND r.reinspection_result = #{reinspectionResult}
AND r.reinspection_time >= (#{dateFrom}::timestamp)
AND r.reinspection_time <= ((#{dateTo}::date) + interval '1 day')
